class Solution:
    def minimumTime(self, n: int, edges, disappear) -> list:
        import heapq
        graph = [[] for _ in range(n)]
        for u, v, l in edges:
            graph[u].append((v, l))
            graph[v].append((u, l))
        INF = float('inf')
        dist = [INF] * n
        dist[0] = 0
        heap = [(0, 0)]
        while heap:
            d, u = heapq.heappop(heap)
            if d > dist[u]:
                continue
            for v, w in graph[u]:
                nd = d + w
                if nd < disappear[v] and nd < dist[v]:
                    dist[v] = nd
                    heapq.heappush(heap, (nd, v))
        return [-1 if dist[i] == INF else dist[i] for i in range(n)]

