var minimumTime = function(n, edges, disappear) {
    const graph = Array.from({length: n}, () => []);
    for (const [u, v, l] of edges) {
        graph[u].push([v, l]);
        graph[v].push([u, l]);
    }
    const INF = Infinity;
    const dist = new Array(n).fill(INF);
    dist[0] = 0;
    // min-heap via sorted approach (small n for stress)
    const heap = [[0, 0]];
    while (heap.length > 0) {
        heap.sort((a, b) => a[0] - b[0]);
        const [d, u] = heap.shift();
        if (d > dist[u]) continue;
        for (const [v, w] of graph[u]) {
            const nd = d + w;
            if (nd < disappear[v] && nd < dist[v]) {
                dist[v] = nd;
                heap.push([nd, v]);
            }
        }
    }
    return dist.map(d => d === INF ? -1 : d);
};
